def main(config):
    scenarios = {
        'ransomware': {'title': 'Ransomware Attack on Critical Infrastructure', 'category': 'malware', 'injects': 5},
        'phishing': {'title': 'Executive Spear-Phishing Campaign', 'category': 'phishing', 'injects': 4},
        'insider_threat': {'title': 'Privileged User Data Exfiltration', 'category': 'insider_threat', 'injects': 4},
        'supply_chain': {'title': 'Third-Party Software Supply Chain Compromise', 'category': 'supply_chain', 'injects': 5},
        'cloud_breach': {'title': 'Cloud Infrastructure Credential Compromise', 'category': 'cloud', 'injects': 4}
    }
    selected = config.get('scenario_type', 'ransomware')
    scenario = scenarios.get(selected, scenarios['ransomware'])
    scenario['scenario_type'] = selected
    return scenario

